if (-not ([System.Management.Automation.PSTypeName]'HoverPanel').Type) {

Add-Type @"
using System;
using System.Drawing;
using System.Drawing.Drawing2D;
using System.Windows.Forms;
using System.Runtime.InteropServices;

public class MainForm : Form {
    private bool  _drag;
    private Point _dragPt;
    private Panel _dragZone;

    public MainForm(Panel dragZone) {
        _dragZone = dragZone;
        FormBorderStyle = FormBorderStyle.None;
        DoubleBuffered  = true;
        SetStyle(ControlStyles.OptimizedDoubleBuffer | ControlStyles.AllPaintingInWmPaint, true);
        _dragZone.MouseDown += (s,e) => { if (e.Button == MouseButtons.Left) { _drag=true; _dragPt=e.Location; }};
        _dragZone.MouseMove += (s,e) => { if (_drag) Location = new Point(Location.X+e.X-_dragPt.X, Location.Y+e.Y-_dragPt.Y); };
        _dragZone.MouseUp   += (s,e) => { _drag=false; };
    }
    protected override void OnResize(EventArgs e) {
        base.OnResize(e);
        if (Width < 1 || Height < 1) return;
        int r = 20;
        GraphicsPath p = new GraphicsPath();
        p.AddArc(0,0,r,r,180,90); p.AddArc(Width-r,0,r,r,270,90);
        p.AddArc(Width-r,Height-r,r,r,0,90); p.AddArc(0,Height-r,r,r,90,90);
        p.CloseFigure();
        Region = new Region(p);
    }
}

public class CloseButton : Control {
    private bool _hover = false;
    public CloseButton() {
        Size = new Size(36, 36);
        Cursor = Cursors.Hand;
        DoubleBuffered = true;
        SetStyle(ControlStyles.OptimizedDoubleBuffer|ControlStyles.AllPaintingInWmPaint|ControlStyles.UserPaint, true);
    }
    protected override void OnMouseEnter(EventArgs e) { _hover=true;  Invalidate(); base.OnMouseEnter(e); }
    protected override void OnMouseLeave(EventArgs e) { _hover=false; Invalidate(); base.OnMouseLeave(e); }
    protected override void OnPaint(PaintEventArgs e) {
        Graphics g = e.Graphics;
        g.SmoothingMode = SmoothingMode.AntiAlias;
        g.Clear(Parent != null ? Parent.BackColor : Color.FromArgb(20,20,24));
        if (_hover) {
            using (SolidBrush hb = new SolidBrush(Color.FromArgb(210,55,20,20)))
                g.FillEllipse(hb, 2, 2, 32, 32);
        }
        Color xc = _hover ? Color.FromArgb(255,110,70) : Color.FromArgb(85,85,98);
        using (Pen p = new Pen(xc, 1.6f)) {
            p.StartCap = LineCap.Round; p.EndCap = LineCap.Round;
            g.DrawLine(p, 12, 12, 24, 24);
            g.DrawLine(p, 24, 12, 12, 24);
        }
    }
}

public class DarkTip : Form {
    private string _text = "";
    private Font   _font;
    private static DarkTip _instance;
    private System.Windows.Forms.Timer _hideTimer;
    private System.Windows.Forms.Timer _fadeTimer;
    private float  _opacity = 0f;
    private bool   _fadingIn = false;

    public static DarkTip Instance {
        get { if (_instance == null || _instance.IsDisposed) _instance = new DarkTip(); return _instance; }
    }

    private DarkTip() {
        FormBorderStyle = FormBorderStyle.None;
        ShowInTaskbar   = false;
        TopMost         = true;
        BackColor       = Color.FromArgb(18, 18, 22);
        Opacity         = 0;
        DoubleBuffered  = true;
        StartPosition   = FormStartPosition.Manual;
        _font = new Font("Segoe UI", 8.5f);
        _hideTimer = new System.Windows.Forms.Timer();
        _hideTimer.Interval = 5500;
        _hideTimer.Tick += (s,e) => { _hideTimer.Stop(); FadeOut(); };
        _fadeTimer = new System.Windows.Forms.Timer();
        _fadeTimer.Interval = 16;
        _fadeTimer.Tick += OnFadeTick;
        SetStyle(ControlStyles.OptimizedDoubleBuffer | ControlStyles.AllPaintingInWmPaint | ControlStyles.UserPaint, true);
    }

    private void OnFadeTick(object sender, EventArgs e) {
        if (_fadingIn) {
            _opacity = Math.Min(1f, _opacity + 0.12f);
            Opacity = _opacity * 0.95;
            if (_opacity >= 1f) _fadeTimer.Stop();
        } else {
            _opacity = Math.Max(0f, _opacity - 0.15f);
            Opacity = _opacity * 0.95;
            if (_opacity <= 0f) { _fadeTimer.Stop(); Hide(); }
        }
    }

    private void FadeOut() {
        _fadingIn = false;
        _fadeTimer.Start();
    }

    public void ShowTip(string text, Control owner) {
        if (string.IsNullOrEmpty(text)) { HideTip(); return; }
        _text = text;
        _hideTimer.Stop();
        SizeF sz = TextRenderer.MeasureText(text, _font, new Size(320, 200),
            TextFormatFlags.WordBreak | TextFormatFlags.Left);
        int w = (int)sz.Width  + 26;
        int h = (int)sz.Height + 20;
        Size = new Size(w, h);
        Point cur  = System.Windows.Forms.Cursor.Position;
        Point pos  = new Point(cur.X + 14, cur.Y + 22);
        Screen scr = Screen.FromPoint(cur);
        if (pos.X + w > scr.WorkingArea.Right)  pos.X = cur.X - w - 4;
        if (pos.Y + h > scr.WorkingArea.Bottom) pos.Y = cur.Y - h - 4;
        Location = pos;
        Invalidate();
        _fadingIn = true;
        _opacity  = 0f;
        Opacity   = 0;
        Show();
        _fadeTimer.Start();
        _hideTimer.Start();
    }

    public void HideTip() { _hideTimer.Stop(); FadeOut(); }

    protected override void OnPaint(PaintEventArgs e) {
        Graphics g = e.Graphics;
        g.SmoothingMode = SmoothingMode.AntiAlias;
        int r = 8;
        Rectangle rc = new Rectangle(0, 0, Width-1, Height-1);
        GraphicsPath path = new GraphicsPath();
        path.AddArc(rc.X, rc.Y, r*2, r*2, 180, 90);
        path.AddArc(rc.Right-r*2, rc.Y, r*2, r*2, 270, 90);
        path.AddArc(rc.Right-r*2, rc.Bottom-r*2, r*2, r*2, 0, 90);
        path.AddArc(rc.X, rc.Bottom-r*2, r*2, r*2, 90, 90);
        path.CloseFigure();
        Region = new Region(path);
        using (SolidBrush bg = new SolidBrush(Color.FromArgb(26, 26, 32)))
            g.FillPath(bg, path);
        using (Pen border = new Pen(Color.FromArgb(75, 75, 90), 1f))
            g.DrawPath(border, path);
        int tipLineStart = r + 2;
        int tipLineEnd   = Width - r - 2;
        if (tipLineEnd > tipLineStart) {
            using (LinearGradientBrush tipLgb = new LinearGradientBrush(
                new Point(tipLineStart, 0), new Point(tipLineEnd, 0),
                Color.FromArgb(255, 95, 45), Color.FromArgb(0, 255, 95, 45))) {
                using (Pen acc = new Pen(tipLgb, 2f))
                    g.DrawLine(acc, tipLineStart, 1, tipLineEnd, 1);
            }
        }
        TextRenderer.DrawText(g, _text, _font,
            new Rectangle(13, 10, Width-26, Height-20),
            Color.FromArgb(205, 205, 215),
            TextFormatFlags.WordBreak | TextFormatFlags.Left);
    }

    protected override bool ShowWithoutActivation { get { return true; } }
    protected override CreateParams CreateParams {
        get {
            CreateParams cp = base.CreateParams;
            cp.ExStyle |= 0x08000000;
            return cp;
        }
    }
}

public class PremiumButton : Button {
    private Color _base, _fg;
    private bool  _hover, _pressed;
    public int CornerRadius = 9;

    public PremiumButton(Color baseColor, Color fgColor) {
        _base = baseColor; _fg = fgColor;
        FlatStyle = FlatStyle.Flat;
        FlatAppearance.BorderSize = 0;
        BackColor = Color.Transparent;
        ForeColor = fgColor;
        Cursor = Cursors.Hand;
        DoubleBuffered = true;
        SetStyle(ControlStyles.OptimizedDoubleBuffer|ControlStyles.AllPaintingInWmPaint|ControlStyles.UserPaint, true);
    }
    protected override void OnMouseEnter(EventArgs e) { _hover = true;  Invalidate(); base.OnMouseEnter(e); }
    protected override void OnMouseLeave(EventArgs e) { _hover = false; _pressed = false; Invalidate(); base.OnMouseLeave(e); }
    protected override void OnMouseDown(MouseEventArgs e) { if (e.Button == MouseButtons.Left) { _pressed = true; Invalidate(); } base.OnMouseDown(e); }
    protected override void OnMouseUp(MouseEventArgs e)   { _pressed = false; Invalidate(); base.OnMouseUp(e); }
    protected override void OnPaintBackground(PaintEventArgs e) {}
    protected override void OnPaint(PaintEventArgs e) {
        Graphics g = e.Graphics;
        g.SmoothingMode = SmoothingMode.AntiAlias;
        g.Clear(Parent != null ? Parent.BackColor : Color.FromArgb(18, 18, 24));
        int r2 = CornerRadius * 2;
        GraphicsPath path = new GraphicsPath();
        path.AddArc(0,0,r2,r2,180,90); path.AddArc(Width-r2,0,r2,r2,270,90);
        path.AddArc(Width-r2,Height-r2,r2,r2,0,90); path.AddArc(0,Height-r2,r2,r2,90,90);
        path.CloseFigure();

        Color fill = _pressed
            ? Color.FromArgb(Math.Max(0,_base.R-22), Math.Max(0,_base.G-22), Math.Max(0,_base.B-22))
            : _hover
                ? Color.FromArgb(Math.Min(255,_base.R+20), Math.Min(255,_base.G+20), Math.Min(255,_base.B+20))
                : _base;

        using (SolidBrush b = new SolidBrush(fill)) g.FillPath(b, path);

        if (!_pressed) {
            GraphicsPath top = new GraphicsPath();
            top.AddArc(1,1,r2-2,r2-2,180,90); top.AddArc(Width-r2,1,r2-2,r2-2,270,90);
            top.AddLine(Width-1, Height/2, 1, Height/2); top.CloseFigure();
            using (SolidBrush sh = new SolidBrush(Color.FromArgb(_hover ? 30 : 18, 255,255,255)))
                g.FillPath(sh, top);
            top.Dispose();
        }

        if (_hover && !_pressed) {
            using (Pen glow = new Pen(Color.FromArgb(55, _fg.R, _fg.G, _fg.B), 1f))
                g.DrawPath(glow, path);
        }

        StringFormat sf = new StringFormat { Alignment = StringAlignment.Center, LineAlignment = StringAlignment.Center };
        Color tc = _pressed ? Color.FromArgb(185, _fg.R, _fg.G, _fg.B) : _fg;
        using (SolidBrush tb = new SolidBrush(tc))
            g.DrawString(Text, Font, tb, new RectangleF(0, _pressed ? 1f : 0f, Width, Height), sf);
    }
}

public class DarkDialog : Form {
    private int  _type;
    private bool _yesNo;
    public  bool Result = false;

    private static Color Accent(int t) {
        switch(t) {
            case 1:  return Color.FromArgb(80, 200, 120);
            case 2:  return Color.FromArgb(255, 175, 50);
            case 3:  return Color.FromArgb(220, 65, 45);
            case 4:  return Color.FromArgb(255, 140, 40);
            default: return Color.FromArgb(88, 158, 255);
        }
    }

    private void DrawIcon(Graphics g, int type, Rectangle b) {
        g.SmoothingMode = SmoothingMode.AntiAlias;
        Color ac = Accent(type);
        float cx = b.X + b.Width  / 2f;
        float cy = b.Y + b.Height / 2f;
        float r  = b.Width / 2f - 1f;

        using (GraphicsPath halo = new GraphicsPath()) {
            halo.AddEllipse(b.X - 5, b.Y - 5, b.Width + 10, b.Height + 10);
            using (PathGradientBrush pg = new PathGradientBrush(halo)) {
                pg.CenterColor    = Color.FromArgb(35, ac.R, ac.G, ac.B);
                pg.SurroundColors = new Color[] { Color.Transparent };
                g.FillPath(pg, halo);
            }
        }

        using (SolidBrush bg = new SolidBrush(Color.FromArgb(38, ac.R, ac.G, ac.B)))
            g.FillEllipse(bg, b.X, b.Y, b.Width, b.Height);
        using (Pen ring = new Pen(Color.FromArgb(170, ac.R, ac.G, ac.B), 1.5f))
            g.DrawEllipse(ring, b.X + 0.75f, b.Y + 0.75f, b.Width - 1.5f, b.Height - 1.5f);

        using (Pen p = new Pen(ac, 2.2f) { StartCap = LineCap.Round, EndCap = LineCap.Round }) {
            if (type == 1 || type == 4) {
                g.DrawLine(p, cx - r*0.33f, cy + r*0.04f, cx - r*0.02f, cy + r*0.36f);
                g.DrawLine(p, cx - r*0.02f, cy + r*0.36f, cx + r*0.40f, cy - r*0.28f);
            } else if (type == 3) {
                g.DrawLine(p, cx - r*0.30f, cy - r*0.30f, cx + r*0.30f, cy + r*0.30f);
                g.DrawLine(p, cx + r*0.30f, cy - r*0.30f, cx - r*0.30f, cy + r*0.30f);
            } else if (type == 2) {
                using (Pen pw = new Pen(ac, 2.4f) { StartCap = LineCap.Round, EndCap = LineCap.Round })
                    g.DrawLine(pw, cx, cy - r*0.30f, cx, cy + r*0.14f);
                using (SolidBrush dot = new SolidBrush(ac))
                    g.FillEllipse(dot, cx - 1.5f, cy + r*0.26f, 3f, 3f);
            } else {
                using (SolidBrush dot = new SolidBrush(ac))
                    g.FillEllipse(dot, cx - 1.6f, cy - r*0.30f, 3.2f, 3.2f);
                using (Pen pi = new Pen(ac, 2.2f) { StartCap = LineCap.Round, EndCap = LineCap.Round })
                    g.DrawLine(pi, cx, cy - r*0.06f, cx, cy + r*0.32f);
            }
        }
    }

    public DarkDialog(string message, int type, bool yesNo) {
        _type = type; _yesNo = yesNo;
        FormBorderStyle = FormBorderStyle.None;
        StartPosition   = FormStartPosition.CenterScreen;
        DoubleBuffered  = true;
        ShowInTaskbar   = false;
        TopMost         = true;
        BackColor       = Color.FromArgb(14, 14, 18);
        int w = 486, h = yesNo ? 214 : 198;
        Size = new Size(w, h);
        SetStyle(ControlStyles.OptimizedDoubleBuffer|ControlStyles.AllPaintingInWmPaint|ControlStyles.UserPaint, true);

        string[] parts = message.Split(new char[]{'\n'}, 2);
        string head    = parts[0].Trim();
        string body    = parts.Length > 1 ? parts[1].Trim() : "";
        bool hasBody   = !string.IsNullOrEmpty(body);

        Label lblHead     = new Label();
        lblHead.Text      = head;
        lblHead.Font      = new Font("Segoe UI Semibold", 10.5f, FontStyle.Bold);
        lblHead.ForeColor = Color.FromArgb(228, 228, 238);
        lblHead.BackColor = Color.Transparent;
        lblHead.Location  = new Point(84, hasBody ? 34 : 46);
        lblHead.Size      = new Size(w - 108, hasBody ? 22 : 50);
        Controls.Add(lblHead);

        if (hasBody) {
            Label lblBody     = new Label();
            lblBody.Text      = body;
            lblBody.Font      = new Font("Segoe UI", 9f);
            lblBody.ForeColor = Color.FromArgb(110, 110, 128);
            lblBody.BackColor = Color.Transparent;
            lblBody.Location  = new Point(84, 60);
            lblBody.Size      = new Size(w - 108, 56);
            Controls.Add(lblBody);
        }

        Color ac = Accent(type);
        if (yesNo) {
            PremiumButton bNo  = MakeBtn("Cancel",  false, ac, w - 340, h - 62);
            PremiumButton bYes = MakeBtn("Confirm", true,  ac, w - 178, h - 62);
            bNo.Click  += (s,e) => { Result = false; Close(); };
            bYes.Click += (s,e) => { Result = true;  Close(); };
            Controls.Add(bNo);
            Controls.Add(bYes);
        } else {
            PremiumButton bOk = MakeBtn("OK", true, ac, w - 178, h - 60);
            bOk.Click += (s,e) => { Result = true; Close(); };
            Controls.Add(bOk);
        }
    }

    private PremiumButton MakeBtn(string txt, bool primary, Color ac, int x, int y) {
        var b = new PremiumButton(
            primary ? Color.FromArgb(Math.Max(0,ac.R-10), Math.Max(0,ac.G-10), Math.Max(0,ac.B-10))
                    : Color.FromArgb(30, 30, 40),
            primary ? Color.FromArgb(12, 12, 16) : Color.FromArgb(148, 148, 165));
        b.Text     = txt;
        b.Font     = new Font("Segoe UI", 9.5f, FontStyle.Bold);
        b.Size     = new Size(152, 38);
        b.Location = new Point(x, y);
        b.Cursor   = Cursors.Hand;
        return b;
    }

    protected override void OnPaint(PaintEventArgs e) {
        Graphics g = e.Graphics;
        g.SmoothingMode     = SmoothingMode.AntiAlias;
        g.InterpolationMode = InterpolationMode.HighQualityBicubic;
        int r = 16;
        GraphicsPath path = new GraphicsPath();
        path.AddArc(0,0,r*2,r*2,180,90); path.AddArc(Width-r*2,0,r*2,r*2,270,90);
        path.AddArc(Width-r*2,Height-r*2,r*2,r*2,0,90); path.AddArc(0,Height-r*2,r*2,r*2,90,90);
        path.CloseFigure();
        Region = new Region(path);

        using (SolidBrush bg = new SolidBrush(Color.FromArgb(19, 19, 25))) g.FillPath(bg, path);
        using (Pen border = new Pen(Color.FromArgb(40, 40, 52), 1f)) g.DrawPath(border, path);

        Color ac = Accent(_type);
        int ls = r + 2, le = Width - r - 2;
        if (le > ls) {
            using (LinearGradientBrush lgb = new LinearGradientBrush(
                new Point(ls, 0), new Point(le, 0),
                Color.FromArgb(210, ac.R, ac.G, ac.B),
                Color.FromArgb(0,   ac.R, ac.G, ac.B))) {
                using (Pen acp = new Pen(lgb, 2f))
                    g.DrawLine(acp, ls, 1, le, 1);
            }
        }

        int sepY = Height - 72;
        Point p1 = new Point(r + 6, sepY), p2 = new Point(Width - r - 6, sepY);
        if (p2.X > p1.X) {
            using (LinearGradientBrush slgb = new LinearGradientBrush(p1, p2,
                Color.Transparent, Color.Transparent)) {
                slgb.LinearColors = new Color[] {
                    Color.FromArgb(0,  45, 45, 58),
                    Color.FromArgb(80, 45, 45, 58),
                    Color.FromArgb(0,  45, 45, 58) };
                using (Pen sp = new Pen(slgb, 1f))
                    g.DrawLine(sp, p1, p2);
            }
        }

        DrawIcon(g, _type, new Rectangle(24, 30, 44, 44));
        base.OnPaint(e);
    }

    protected override bool ProcessCmdKey(ref Message msg, Keys keyData) {
        if (keyData == Keys.Escape) { Result = false; Close(); return true; }
        if (keyData == Keys.Return && !_yesNo) { Result = true; Close(); return true; }
        return base.ProcessCmdKey(ref msg, keyData);
    }

    public static void Show(string message, int type = 0) {
        using (DarkDialog d = new DarkDialog(message, type, false)) d.ShowDialog();
    }
    public static bool Confirm(string message) {
        using (DarkDialog d = new DarkDialog(message, 4, true)) { d.ShowDialog(); return d.Result; }
    }
}

public class SilentScrollPanel : Panel {
    [DllImport("user32.dll")]
    private static extern int ShowScrollBar(IntPtr hWnd, int wBar, bool bShow);
    private const int SB_BOTH = 3;
    private int _scrollY = 0, _innerH = 0, _scrollSpeed = 45;

    public SilentScrollPanel() {
        DoubleBuffered = true;
        SetStyle(ControlStyles.OptimizedDoubleBuffer | ControlStyles.AllPaintingInWmPaint, true);
        AutoScroll = false;
    }
    public void SetInnerHeight(int h) { _innerH = h; }
    protected override void OnHandleCreated(EventArgs e) { base.OnHandleCreated(e); ShowScrollBar(Handle, SB_BOTH, false); }
    protected override void OnMouseWheel(MouseEventArgs e) { ScrollBy(-e.Delta / 120 * _scrollSpeed); }

    public void ScrollBy(int delta) {
        int max = Math.Max(0, _innerH - Height);
        _scrollY = Math.Max(0, Math.Min(_scrollY + delta, max));
        foreach (Control c in Controls) { if (c.Tag != null) c.Top = (int)c.Tag + (-_scrollY); }
    }
    public void SnapshotPositions() { foreach (Control c in Controls) c.Tag = c.Top; }

    protected override void WndProc(ref Message m) {
        if (m.Msg == 0x020A) {
            short rawDelta = (short)((m.WParam.ToInt64() >> 16) & 0xFFFF);
            ScrollBy(-(int)rawDelta / 120 * _scrollSpeed);
            return;
        }
        base.WndProc(ref m);
    }
}

public class ToggleSwitch : Control {
    private bool _on = false, _hover = false;
    public bool IsOn { get { return _on; } set { _on = value; Invalidate(); } }
    public event EventHandler Toggled;

    public ToggleSwitch() {
        Size = new Size(52, 26); Cursor = Cursors.Hand; DoubleBuffered = true;
        SetStyle(ControlStyles.OptimizedDoubleBuffer|ControlStyles.AllPaintingInWmPaint|ControlStyles.UserPaint, true);
    }
    protected override void OnMouseEnter(EventArgs e) { _hover=true;  Invalidate(); base.OnMouseEnter(e); }
    protected override void OnMouseLeave(EventArgs e) { _hover=false; Invalidate(); base.OnMouseLeave(e); }
    protected override void OnClick(EventArgs e) { _on=!_on; Invalidate(); if(Toggled!=null) Toggled(this,EventArgs.Empty); base.OnClick(e); }

    protected override void OnPaint(PaintEventArgs e) {
        Graphics g = e.Graphics;
        g.SmoothingMode = SmoothingMode.AntiAlias;
        g.InterpolationMode = InterpolationMode.HighQualityBicubic;
        g.Clear(Parent != null ? Parent.BackColor : Color.Transparent);
        int tw=Width-2, th=Height-2, r=th;
        Color baseOn  = _hover ? Color.FromArgb(100,215,135) : Color.FromArgb(80,200,120);
        Color baseOff = _hover ? Color.FromArgb(72,72,82)    : Color.FromArgb(55,55,68);
        using (GraphicsPath tp = new GraphicsPath()) {
            tp.AddArc(1,1,r,r,90,180); tp.AddArc(tw-r+1,1,r,r,270,180); tp.CloseFigure();
            using (SolidBrush b = new SolidBrush(_on ? baseOn : baseOff)) g.FillPath(b, tp);
        }
        int thumbD=th-6, thumbX=_on?(tw-thumbD-2):4, thumbY=4;
        if (_on) {
            using (GraphicsPath glow = new GraphicsPath()) {
                glow.AddEllipse(thumbX-3,thumbY-3,thumbD+6,thumbD+6);
                using (PathGradientBrush gb = new PathGradientBrush(glow)) {
                    gb.CenterColor=Color.FromArgb(60,120,255,160); gb.SurroundColors=new Color[]{Color.Transparent}; g.FillPath(gb,glow);
                }
            }
        }
        using (GraphicsPath th2 = new GraphicsPath()) {
            th2.AddEllipse(thumbX,thumbY,thumbD,thumbD);
            using (SolidBrush tb=new SolidBrush(Color.FromArgb(235,235,240))) g.FillPath(tb,th2);
            using (Pen pe=new Pen(Color.FromArgb(30,0,0,0),1f)) g.DrawPath(pe,th2);
        }
    }
}

public class HoverPanel : Panel {
    private Color _baseColor;
    private Color _hoverColor;
    private bool  _isHovered = false;
    private System.Windows.Forms.Timer _leaveTimer;
    private int   _leaveTickCount = 0;
    private const int LeaveTickMax = 5;

    public HoverPanel(Color baseColor) {
        _baseColor  = baseColor;
        _hoverColor = Color.FromArgb(
            Math.Min(255, baseColor.R + 14),
            Math.Min(255, baseColor.G + 14),
            Math.Min(255, baseColor.B + 20));
        BackColor   = baseColor;
        DoubleBuffered = true;
        SetStyle(ControlStyles.OptimizedDoubleBuffer|ControlStyles.AllPaintingInWmPaint, true);
        _leaveTimer = new System.Windows.Forms.Timer();
        _leaveTimer.Interval = 20;
        _leaveTimer.Tick += OnLeaveTimerTick;
    }

    private void OnLeaveTimerTick(object sender, EventArgs e) {
        Point clientPos = PointToClient(System.Windows.Forms.Cursor.Position);
        if (!ClientRectangle.Contains(clientPos)) {
            _leaveTickCount++;
            if (_leaveTickCount >= LeaveTickMax) {
                _leaveTimer.Stop();
                _leaveTickCount = 0;
                if (_isHovered) { _isHovered = false; ApplyColor(_baseColor); }
            }
        } else {
            _leaveTickCount = 0;
        }
    }

    private void ApplyColor(Color c) {
        BackColor = c;
        foreach (Control child in Controls) {
            if (child is ToggleSwitch) continue;
            child.BackColor = c;
        }
    }

    protected override void OnMouseEnter(EventArgs e) {
        _leaveTimer.Stop();
        _leaveTickCount = 0;
        if (!_isHovered) { _isHovered = true; ApplyColor(_hoverColor); }
        base.OnMouseEnter(e);
    }

    protected override void OnMouseLeave(EventArgs e) {
        _leaveTickCount = 0;
        _leaveTimer.Start();
        base.OnMouseLeave(e);
    }

    protected override void OnControlAdded(ControlEventArgs e) {
        base.OnControlAdded(e);
        e.Control.MouseEnter += ChildMouseEnter;
        e.Control.MouseLeave += ChildMouseLeave;
    }

    private void ChildMouseEnter(object sender, EventArgs e) {
        _leaveTimer.Stop();
        _leaveTickCount = 0;
        if (!_isHovered) { _isHovered = true; ApplyColor(_hoverColor); }
    }

    private void ChildMouseLeave(object sender, EventArgs e) {
        _leaveTickCount = 0;
        _leaveTimer.Start();
    }
}

public class CardPanel : Panel {
    public int   CornerRadius = 12;
    public Color BorderColor  = Color.FromArgb(52,52,60);
    public Color HeaderColor  = Color.FromArgb(255,95,45);

    public CardPanel() {
        DoubleBuffered = true;
        SetStyle(ControlStyles.OptimizedDoubleBuffer|ControlStyles.AllPaintingInWmPaint|ControlStyles.UserPaint|ControlStyles.ResizeRedraw, true);
        Padding = new Padding(0);
    }
    protected override void OnPaintBackground(PaintEventArgs e) {}
    protected override void OnPaint(PaintEventArgs e) {
        Graphics g = e.Graphics;
        g.SmoothingMode = SmoothingMode.AntiAlias;
        g.InterpolationMode = InterpolationMode.HighQualityBicubic;
        int r = CornerRadius * 2;
        GraphicsPath path = new GraphicsPath();
        path.AddArc(0,0,r,r,180,90); path.AddArc(Width-r,0,r,r,270,90);
        path.AddArc(Width-r,Height-r,r,r,0,90); path.AddArc(0,Height-r,r,r,90,90);
        path.CloseFigure();
        using (SolidBrush bg = new SolidBrush(BackColor)) g.FillPath(bg, path);
        using (Pen border = new Pen(BorderColor, 1f)) g.DrawPath(border, path);
        int lineStartX = CornerRadius + 2;
        int lineEndX   = Width - CornerRadius - 2;
        if (lineEndX > lineStartX) {
            using (LinearGradientBrush lgb = new LinearGradientBrush(
                new Point(lineStartX, 0), new Point(lineEndX, 0),
                HeaderColor, Color.FromArgb(0, HeaderColor.R, HeaderColor.G, HeaderColor.B))) {
                using (Pen accent = new Pen(lgb, 2.5f))
                    g.DrawLine(accent, lineStartX, 1, lineEndX, 1);
            }
        }
        Region = new Region(path);
        base.OnPaint(e);
    }
}

public class RoundButton : Button {
    public int CornerRadius = 8;
    private bool  _hover = false;
    private bool  _pressed = false;
    private Color _baseColor, _textColor;

    public RoundButton(Color baseColor, Color textColor) {
        _baseColor = baseColor; _textColor = textColor;
        FlatStyle = FlatStyle.Flat; FlatAppearance.BorderSize = 0;
        BackColor = Color.Transparent; ForeColor = textColor; Cursor = Cursors.Hand;
        DoubleBuffered = true;
        SetStyle(ControlStyles.OptimizedDoubleBuffer|ControlStyles.AllPaintingInWmPaint|ControlStyles.UserPaint, true);
    }
    protected override void OnMouseEnter(EventArgs e) { _hover=true;  Invalidate(); base.OnMouseEnter(e); }
    protected override void OnMouseLeave(EventArgs e) { _hover=false; _pressed=false; Invalidate(); base.OnMouseLeave(e); }
    protected override void OnMouseDown(MouseEventArgs e) { if(e.Button==MouseButtons.Left){_pressed=true; Invalidate();} base.OnMouseDown(e); }
    protected override void OnMouseUp(MouseEventArgs e)   { _pressed=false; Invalidate(); base.OnMouseUp(e); }
    protected override void OnPaintBackground(PaintEventArgs e) {}
    protected override void OnPaint(PaintEventArgs e) {
        Graphics g = e.Graphics;
        g.SmoothingMode = SmoothingMode.AntiAlias;
        g.Clear(Parent != null ? Parent.BackColor : Color.FromArgb(22,22,22));
        int r = CornerRadius * 2;
        GraphicsPath path = new GraphicsPath();
        path.AddArc(0,0,r,r,180,90); path.AddArc(Width-r,0,r,r,270,90);
        path.AddArc(Width-r,Height-r,r,r,0,90); path.AddArc(0,Height-r,r,r,90,90);
        path.CloseFigure();
        Color fill;
        if (_pressed) {
            fill = Color.FromArgb(Math.Max(0,_baseColor.R-14), Math.Max(0,_baseColor.G-14), Math.Max(0,_baseColor.B-14));
        } else if (_hover) {
            fill = Color.FromArgb(Math.Min(255,_baseColor.R+22), Math.Min(255,_baseColor.G+22), Math.Min(255,_baseColor.B+22));
        } else {
            fill = _baseColor;
        }
        using (SolidBrush b = new SolidBrush(fill)) g.FillPath(b, path);
        if (!_pressed) {
            GraphicsPath topPath = new GraphicsPath();
            topPath.AddArc(1,1,r-1,r-1,180,90); topPath.AddArc(Width-r,1,r-1,r-1,270,90);
            topPath.AddLine(Width-1, Height/2, 1, Height/2);
            topPath.CloseFigure();
            using (SolidBrush topBrush = new SolidBrush(Color.FromArgb(_hover?32:20, 255,255,255)))
                g.FillPath(topBrush, topPath);
            topPath.Dispose();
        }
        if (_hover && !_pressed) {
            using (Pen border = new Pen(Color.FromArgb(55, _textColor.R, _textColor.G, _textColor.B), 1f))
                g.DrawPath(border, path);
        }
        StringFormat sf = new StringFormat { Alignment=StringAlignment.Center, LineAlignment=StringAlignment.Center };
        Color tc = _pressed ? Color.FromArgb(200, _textColor.R, _textColor.G, _textColor.B) : _textColor;
        using (SolidBrush tb = new SolidBrush(tc))
            g.DrawString(Text, Font, tb, new RectangleF(0, _pressed?1:0, Width, Height), sf);
    }
}

public class DotBadge : Control {
    public bool Active = false;
    private float _glowAlpha = 0f;
    private System.Windows.Forms.Timer _glowTimer;
    private bool _glowIn = true;

    public DotBadge() {
        Size = new Size(10, 10);
        SetStyle(ControlStyles.OptimizedDoubleBuffer|ControlStyles.AllPaintingInWmPaint|ControlStyles.UserPaint, true);
        _glowTimer = new System.Windows.Forms.Timer();
        _glowTimer.Interval = 40;
        _glowTimer.Tick += (s,e) => {
            if (!Active) { _glowTimer.Stop(); _glowAlpha=0; Invalidate(); return; }
            if (_glowIn) { _glowAlpha = Math.Min(1f, _glowAlpha + 0.06f); if (_glowAlpha>=1f) _glowIn=false; }
            else         { _glowAlpha = Math.Max(0f, _glowAlpha - 0.06f); if (_glowAlpha<=0f) _glowIn=true;  }
            Invalidate();
        };
    }

    private bool _wasActive = false;
    protected override void OnPaint(PaintEventArgs e) {
        if (Active != _wasActive) {
            _wasActive = Active;
            if (Active) { _glowIn=true; _glowAlpha=0; _glowTimer.Start(); }
            else        { _glowTimer.Stop(); _glowAlpha=0; }
        }
        e.Graphics.SmoothingMode = SmoothingMode.AntiAlias;
        Color c = Active ? Color.FromArgb(80,200,120) : Color.FromArgb(52,52,62);
        e.Graphics.Clear(Parent != null ? Parent.BackColor : Color.Transparent);
        if (Active && _glowAlpha > 0) {
            int ga = (int)(_glowAlpha * 55);
            using (SolidBrush gb = new SolidBrush(Color.FromArgb(ga, 80,200,120)))
                e.Graphics.FillEllipse(gb, -1, -1, 11, 11);
        }
        using (SolidBrush b = new SolidBrush(c)) e.Graphics.FillEllipse(b, 1, 1, 7, 7);
    }
}

public class GradientSep : Control {
    public Color AccentColor = Color.FromArgb(255, 95, 45);
    public GradientSep() {
        Height = 2;
        SetStyle(ControlStyles.OptimizedDoubleBuffer|ControlStyles.AllPaintingInWmPaint|ControlStyles.UserPaint, true);
        DoubleBuffered = true;
    }
    protected override void OnPaint(PaintEventArgs e) {
        if (Width < 2) return;
        using (LinearGradientBrush lgb = new LinearGradientBrush(
            new Point(0, 0), new Point(Width, 0),
            Color.FromArgb(180, AccentColor.R, AccentColor.G, AccentColor.B),
            Color.FromArgb(0,   AccentColor.R, AccentColor.G, AccentColor.B))) {
            e.Graphics.FillRectangle(lgb, 0, 0, Width, Height);
        }
    }
    protected override void OnResize(EventArgs e) { base.OnResize(e); Invalidate(); }
}
