function Ensure-RegPath {
    if (-not (Test-Path $REG_PATH)) { New-Item -Path $REG_PATH -Force | Out-Null }
}
function Ensure-ExtSettPath {
    if (-not (Test-Path $REG_EXT_SETT)) { New-Item -Path $REG_EXT_SETT -Force | Out-Null }
}
function Clean-LegacyKeys {
    foreach ($k in @("ExtensionToolbar","IPFSEnabled","DefaultBraveHttpsUpgradeSetting","DefaultBraveRemember1PStorageSetting")) {
        Remove-ItemProperty -Path $REG_PATH -Name $k -ErrorAction SilentlyContinue
    }
}
function Apply-Feature([hashtable]$f) {
    Ensure-RegPath
    if ($f.Type -eq "ExtForceList") {
        if (-not (Test-Path $REG_EXT_FORCE)) { New-Item -Path $REG_EXT_FORCE -Force | Out-Null }
        $existing = (Get-Item -Path $REG_EXT_FORCE -ErrorAction SilentlyContinue).Property
        [int]$nextIdx = 1
        if ($existing) {
            $nums = $existing | Where-Object { $_ -match '^\d+$' } | ForEach-Object { [int]$_ }
            if ($nums) { $nextIdx = ($nums | Measure-Object -Maximum).Maximum + 1 }
            foreach ($prop in $existing) {
                $val = (Get-ItemProperty -Path $REG_EXT_FORCE -Name $prop -ErrorAction SilentlyContinue).$prop
                if ($val -eq $f.Value) {
                    $extId = ($f.Value -split ";")[0].Trim()
                    Ensure-ExtSettPath
                    Set-ItemProperty -Path $REG_EXT_SETT -Name $extId -Value '{"toolbar_pin": "force_pinned"}' -Type String -Force
                    Write-Host "[APPLY]  $($f.Key) = $($f.Value)" -ForegroundColor Green
                    return
                }
            }
        }
        Set-ItemProperty -Path $REG_EXT_FORCE -Name "$nextIdx" -Value $f.Value -Type String -Force
        $extId = ($f.Value -split ";")[0].Trim()
        Ensure-ExtSettPath
        Set-ItemProperty -Path $REG_EXT_SETT -Name $extId -Value '{"toolbar_pin": "force_pinned"}' -Type String -Force
    } elseif ($f.Type -eq "MultiString") {
        Set-ItemProperty -Path $REG_PATH -Name $f.Key -Value $f.Value -Type MultiString -Force
    } elseif ($f.Type -eq "String") {
        Set-ItemProperty -Path $REG_PATH -Name $f.Key -Value $f.Value -Type String -Force
    } else {
        Set-ItemProperty -Path $REG_PATH -Name $f.Key -Value $f.Value -Type DWord -Force
    }
}

function Remove-Feature([hashtable]$f) {
    if ($f.Type -eq "ExtForceList") {
        if (Test-Path $REG_EXT_FORCE) {
            $existing = (Get-Item -Path $REG_EXT_FORCE -ErrorAction SilentlyContinue).Property
            if ($existing) {
                foreach ($prop in $existing) {
                    $val = (Get-ItemProperty -Path $REG_EXT_FORCE -Name $prop -ErrorAction SilentlyContinue).$prop
                    if ($val -eq $f.Value) {
                        Remove-ItemProperty -Path $REG_EXT_FORCE -Name $prop -ErrorAction SilentlyContinue
                        Write-Host "[REMOVE] $($f.Key)" -ForegroundColor DarkYellow
                    }
                }
            }
            $extId = ($f.Value -split ";")[0].Trim()
            if (Test-Path $REG_EXT_SETT) {
                Remove-ItemProperty -Path $REG_EXT_SETT -Name $extId -ErrorAction SilentlyContinue
            }
        }
    } elseif ($f.Type -eq "MultiString" -or $f.Type -eq "String" -or $f.Type -eq "DWord") {
        if (Test-Path $REG_PATH) {
            Remove-ItemProperty -Path $REG_PATH -Name $f.Key -ErrorAction SilentlyContinue
        }
    }
}

function Set-DnsMode([string]$m) {
    Ensure-RegPath
    Set-ItemProperty -Path $REG_PATH -Name "DnsOverHttpsMode" -Value $m -Type String -Force
}

function Get-AppliedKeys {
    $applied = @{}
    if (-not (Test-Path $REG_PATH)) { return $applied }
    $props = Get-Item -Path $REG_PATH -ErrorAction SilentlyContinue
    if ($props) {
        foreach ($p in $props.Property) {
            $applied[$p] = (Get-ItemProperty -Path $REG_PATH -Name $p -ErrorAction SilentlyContinue).$p
        }
    }
    if (Test-Path $REG_EXT_FORCE) {
        $extProps = Get-Item -Path $REG_EXT_FORCE -ErrorAction SilentlyContinue
        if ($extProps) {
            foreach ($p in $extProps.Property) {
                $val = (Get-ItemProperty -Path $REG_EXT_FORCE -Name $p -ErrorAction SilentlyContinue).$p
                if ($val) {
                    $extId = ($val -split ";")[0].Trim()
                    $applied["ext:$extId"] = $val
                }
            }
        }
    }
    return $applied
}

function Get-FeatureLookupKey([hashtable]$f) {
    if ($f.Type -eq "ExtForceList") {
        $extId = ($f.Value -split ";")[0].Trim()
        return "ext:$extId"
    }
    return $f.Key
}

