$lblTitle           = New-Object System.Windows.Forms.Label
$lblTitle.Text      = "Brave Optimizer"
$lblTitle.Font      = $F_TITLE
$lblTitle.ForeColor = $C_ACCENT
$lblTitle.AutoSize  = $true
