$lblSub           = New-Object System.Windows.Forms.Label
$lblSub.Text      = "The advanced optimization solution for Brave. Eliminate unnecessary processes, maximize performance, and ensure your privacy is secure."
$lblSub.Font      = $F_VER
$lblSub.ForeColor = $C_MUTED
$lblSub.AutoSize  = $true
$lblSub.Location  = New-Object System.Drawing.Point(($titleOffX + 2), 43)
$lblSub.BackColor = [System.Drawing.Color]::Transparent
$headerPanel.Controls.Add($lblSub)

$lblVer           = New-Object System.Windows.Forms.Label
$lblVer.Font      = New-Object System.Drawing.Font("Segoe UI",7.5)
$lblVer.ForeColor = [System.Drawing.Color]::FromArgb(255,60,60,72)
$lblVer.AutoSize  = $true
$lblVer.Location  = New-Object System.Drawing.Point(($FW - 80), 28)
$lblVer.BackColor = [System.Drawing.Color]::Transparent
$headerPanel.Controls.Add($lblVer)

$btnX          = New-Object CloseButton
$btnX.Location = New-Object System.Drawing.Point(($FW - 46), 16)
$btnX.Add_Click({ $form.Close() })
$headerPanel.Controls.Add($btnX)

$scroll           = New-Object SilentScrollPanel
$scroll.Location  = New-Object System.Drawing.Point(0, $HDR_H)
$scroll.Size      = New-Object System.Drawing.Size($FW, $SCROLL_H)
$scroll.BackColor = $C_BG
$form.Controls.Add($scroll)

$wheelHandler = [System.Windows.Forms.MouseEventHandler]{
    param($s, $e)
    $scroll.ScrollBy(-$e.Delta / 120 * 45)
}
$scroll.Add_MouseWheel($wheelHandler)

$appliedKeys = Get-AppliedKeys

$col0_x = $padL
$col1_x = $padL + $colW + $gap
$col2_x = $padL + $colW + $gap + $colW + $gap
$colXs  = @($col0_x, $col1_x, $col2_x)
$colYs  = @(16, 16, 16)

$colAssign = @{
    "Extensions"               = 0
    "Telemetry and Reporting"  = 0
    "Privacy and Security"     = 1
    "Brave Features"           = 2
    "New Tab and UI"           = 0
    "Performance and Bloat"    = 2
}

$allToggles  = @()
$allDots     = @()
$allFeatKeys = @()
$allFeatVals = @()
$sectionKeys = @($sections.Keys)
$tip         = [DarkTip]::Instance

for ($si = 0; $si -lt $sectionKeys.Count; $si++) {
    $sName = $sectionKeys[$si]
    $feats = $sections[$sName]
    [int]$cardH = 46 + ($feats.Count * $rowH) + 10
    [int]$col   = if ($colAssign.ContainsKey($sName)) { $colAssign[$sName] } else { $si % 3 }
    [int]$cx    = $colXs[$col]
    [int]$cy    = $colYs[$col]

    $card           = New-Object CardPanel
    $card.Location  = New-Object System.Drawing.Point($cx, $cy)
    $card.Size      = New-Object System.Drawing.Size($colW, $cardH)
    $card.BackColor = $C_CARD
    $scroll.Controls.Add($card)
    $card.Add_MouseWheel($wheelHandler)

    $lCat           = New-Object System.Windows.Forms.Label
    $lCat.Text      = $sName.ToUpper()
    $lCat.Font      = $F_CAT
    $lCat.ForeColor = $C_ACCENT
    $lCat.Location  = New-Object System.Drawing.Point(16, 15)
    $lCat.AutoSize  = $true
    $lCat.BackColor = [System.Drawing.Color]::Transparent
    $card.Controls.Add($lCat)
    $lCat.Add_MouseWheel($wheelHandler)

    [int]$ry   = 42
    [bool]$alt = $false

    foreach ($feat in $feats) {
        $capturedTip = [string]$feat.Tip
        $lookupKey   = Get-FeatureLookupKey -f $feat
        $isApplied   = $appliedKeys.ContainsKey($lookupKey) -and ("$($appliedKeys[$lookupKey])" -eq "$($feat.Value)")
        $rowBase     = if ($alt) { $C_ROW } else { $C_ROWALT }
        $alt         = -not $alt

        $rowPan          = New-Object HoverPanel($rowBase)
        $rowPan.Location = New-Object System.Drawing.Point(8, $ry)
        $rowPan.Size     = New-Object System.Drawing.Size(($colW - 16), $rowH)
        $card.Controls.Add($rowPan)
        $rowPan.Add_MouseWheel($wheelHandler)

        if ($capturedTip) {
            $rowPan.Add_MouseEnter([scriptblock]::Create("`$tip.ShowTip('$($capturedTip -replace "'", " ")' , `$this)"))
            $rowPan.Add_MouseLeave({ $tip.HideTip() })
        }

        $dot           = New-Object DotBadge
        $dot.Active    = $isApplied
        $dot.Location  = New-Object System.Drawing.Point(8, 16)
        $dot.BackColor = $rowBase
        $rowPan.Controls.Add($dot)
        $dot.Add_MouseWheel($wheelHandler)
        $allDots     += $dot
        $allFeatKeys += $lookupKey
        $allFeatVals += $feat.Value

        $lItem           = New-Object System.Windows.Forms.Label
        $lItem.Text      = $feat.Name
        $lItem.Font      = $F_ITEM
        $lItem.ForeColor = $C_WHITE
        $lItem.Location  = New-Object System.Drawing.Point(22, 12)
        $lItem.Size      = New-Object System.Drawing.Size(($colW - 96), 20)
        $lItem.BackColor = [System.Drawing.Color]::Transparent
        $rowPan.Controls.Add($lItem)
        $lItem.Add_MouseWheel($wheelHandler)

        if ($capturedTip) {
            $lItem.Add_MouseEnter([scriptblock]::Create("`$tip.ShowTip('$($capturedTip -replace "'", " ")' , `$this)"))
            $lItem.Add_MouseLeave({ $tip.HideTip() })
        }

        $tog          = New-Object ToggleSwitch
        $tog.IsOn     = $isApplied
        $tog.Tag      = $feat
        [int]$togX    = $colW - 16 - 60
        $tog.Location = New-Object System.Drawing.Point($togX, 8)
        $rowPan.Controls.Add($tog)
        $tog.Add_MouseWheel($wheelHandler)

        $allToggles += $tog
        $ry += $rowH
    }

    $colYs[$col] += $cardH + $gap
}

[int]$innerH = ([Math]::Max($colYs[0], [Math]::Max($colYs[1], $colYs[2]))) + 16
$scroll.SetInnerHeight($innerH)
$scroll.SnapshotPositions()

$foot           = New-Object System.Windows.Forms.Panel
$foot.Location  = New-Object System.Drawing.Point(0, ($FH - $FOOT_H))
$foot.Size      = New-Object System.Drawing.Size($FW, $FOOT_H)
$foot.BackColor = $C_FOOT
$form.Controls.Add($foot)

$sepFoot          = New-Object GradientSep
$sepFoot.Size     = New-Object System.Drawing.Size($FW, 2)
$sepFoot.Location = New-Object System.Drawing.Point(0, 0)
$foot.Controls.Add($sepFoot)

$lblDnsLbl           = New-Object System.Windows.Forms.Label
$lblDnsLbl.Text      = "DNS OVER HTTPS"
$lblDnsLbl.Font      = New-Object System.Drawing.Font("Segoe UI", 7, [System.Drawing.FontStyle]::Bold)
$lblDnsLbl.ForeColor = $C_MUTED
$lblDnsLbl.AutoSize  = $true
$lblDnsLbl.Location  = New-Object System.Drawing.Point(22, 14)
$lblDnsLbl.BackColor = [System.Drawing.Color]::Transparent
$foot.Controls.Add($lblDnsLbl)

$dnsDrop               = New-Object System.Windows.Forms.ComboBox
$dnsDrop.Location      = New-Object System.Drawing.Point(22, 32)
$dnsDrop.Size          = New-Object System.Drawing.Size(130, 28)
$dnsDrop.FlatStyle     = [System.Windows.Forms.FlatStyle]::Flat
$dnsDrop.BackColor     = $C_ROW
$dnsDrop.ForeColor     = $C_WHITE
$dnsDrop.Font          = $F_DNS
$dnsDrop.DropDownStyle = [System.Windows.Forms.ComboBoxStyle]::DropDownList
$dnsDrop.Items.AddRange(@("(unchanged)", "automatic", "off", "custom"))
$dnsDrop.SelectedIndex = 0
$foot.Controls.Add($dnsDrop)
$dnsDrop.Add_MouseEnter({ $tip.ShowTip("automatic = DoH if available | off = classic DNS | custom = set URL in brave://settings/security", $dnsDrop) })
$dnsDrop.Add_MouseLeave({ $tip.HideTip() })

function New-RBtn([string]$txt, [int]$idx, [System.Drawing.Color]$bg, [System.Drawing.Color]$fg) {
    $b               = New-Object RoundButton($bg, $fg)
    $b.Text          = $txt
    $b.Font          = $F_BTN
    $b.Location      = New-Object System.Drawing.Point(($BTN_LEFT + $idx * ($BTN_W + $BTN_GAP)), 18)
    $b.Size          = New-Object System.Drawing.Size($BTN_W, 42)
    $b.CornerRadius  = 8
    $foot.Controls.Add($b)
    return $b
}

$btnPreset = New-RBtn "Select Preset" 0 ([System.Drawing.Color]::FromArgb(255,34,34,46))  $C_WHITE
$btnExport = New-RBtn "Export"        1 ([System.Drawing.Color]::FromArgb(255,26,44,74))  $C_BLUE
$btnImport = New-RBtn "Import"        2 ([System.Drawing.Color]::FromArgb(255,34,34,46))  $C_WHITE
$btnApply  = New-RBtn "Apply"         3 ([System.Drawing.Color]::FromArgb(255,18,50,30))  $C_GREEN
$btnReset  = New-RBtn "Reset All"     4 ([System.Drawing.Color]::FromArgb(255,54,14,14))  $C_RED

$btnPreset.Add_MouseEnter({ $tip.ShowTip("Load a preset configuration: Minimal, Balanced, or Full Privacy.", $btnPreset) })
$btnPreset.Add_MouseLeave({ $tip.HideTip() })
$btnExport.Add_MouseEnter({ $tip.ShowTip("Save current selection to a JSON configuration file.", $btnExport) })
$btnExport.Add_MouseLeave({ $tip.HideTip() })
$btnImport.Add_MouseEnter({ $tip.ShowTip("Load a previously exported JSON configuration.", $btnImport) })
$btnImport.Add_MouseLeave({ $tip.HideTip() })
$btnApply.Add_MouseEnter({  $tip.ShowTip("Write selected policies to the Windows registry. Restart Brave to apply.", $btnApply) })
$btnApply.Add_MouseLeave({  $tip.HideTip() })
$btnReset.Add_MouseEnter({  $tip.ShowTip("Remove ALL Brave policies from the registry and reset all toggles.", $btnReset) })
$btnReset.Add_MouseLeave({  $tip.HideTip() })

$script:PRESET_URLS = @{
    "Privacy"                 = "https://raw.githubusercontent.com/insovs/Brave-Optimizer/refs/heads/main/Presets/Privacy%20Preset.json"
    "Performance"             = "https://raw.githubusercontent.com/insovs/Brave-Optimizer/refs/heads/main/Presets/Performance%20Preset.json"
    "Performance and Privacy" = "https://raw.githubusercontent.com/insovs/Brave-Optimizer/refs/heads/main/Presets/Performance%20and%20Privacy%20Preset.json"
}

function Load-PresetFromUrl([string]$url) {
    try {
        $wc          = New-Object System.Net.WebClient
        $wc.Encoding = [System.Text.Encoding]::UTF8
        $wc.Headers.Add("User-Agent", "BraveOptimizer/1.0")
        return ($wc.DownloadString($url) | ConvertFrom-Json)
    } catch {
        [DarkDialog]::Show("Cannot load preset:`n$($_.Exception.Message)", 3)
        return $null
    }
}

function Apply-PresetConfig([PSCustomObject]$cfg) {
    foreach ($t in $allToggles) { $t.IsOn = $false }
    if ($cfg.Features -ne $null) {
        foreach ($key in $cfg.Features) {
            $keyStr = [string]$key
            for ($ti = 0; $ti -lt $allToggles.Count; $ti++) {
                if (([string]$allFeatKeys[$ti]) -eq $keyStr -or ([string]$allToggles[$ti].Tag.Key) -eq $keyStr) {
                    $allToggles[$ti].IsOn = $true
                    break
                }
            }
        }
    }
    if ($cfg.DnsMode) {
        $idx = $dnsDrop.Items.IndexOf([string]$cfg.DnsMode)
        if ($idx -ge 0) { $dnsDrop.SelectedIndex = $idx }
    }
    return [int]($allToggles | Where-Object { $_.IsOn }).Count
}

$btnPreset.Add_Click({
    $ctxMenu                 = New-Object System.Windows.Forms.ContextMenuStrip
    $ctxMenu.BackColor       = [System.Drawing.Color]::FromArgb(255,28,28,36)
    $ctxMenu.ForeColor       = $C_WHITE
    $ctxMenu.Font            = $F_BTN
    $ctxMenu.ShowImageMargin = $false

    foreach ($pName in $script:PRESET_URLS.Keys) {
        $item           = New-Object System.Windows.Forms.ToolStripMenuItem
        $item.Text      = $pName
        $item.Tag       = $script:PRESET_URLS[$pName]
        $item.BackColor = [System.Drawing.Color]::FromArgb(255,28,28,36)
        $item.ForeColor = $C_WHITE
        $item.Add_Click({
            $url  = [string]$this.Tag
            $name = [string]$this.Text
            $btnPreset.Text    = "Loading..."
            $btnPreset.Enabled = $false
            [System.Windows.Forms.Application]::DoEvents()
            $cfg = Load-PresetFromUrl -url $url
            $btnPreset.Text    = "Select Preset"
            $btnPreset.Enabled = $true
            if ($cfg -eq $null) { return }
            $n = Apply-PresetConfig -cfg $cfg
            [DarkDialog]::Show("Preset `"$name`" loaded.`nClick Apply to write to registry for apply.", 1)
        })
        $ctxMenu.Items.Add($item) | Out-Null
    }

    $pt = $btnPreset.PointToScreen([System.Drawing.Point]::new(0, -($ctxMenu.Items.Count * 30 + 8)))
    $ctxMenu.Show($pt)
})

$btnApply.Add_Click({
    Ensure-RegPath
    Clean-LegacyKeys
    $errors      = @()
    $logLines    = @()
    $btnApply.Text    = "Applying..."
    $btnApply.Enabled = $false
    [System.Windows.Forms.Application]::DoEvents()

    $beforeApply = Get-AppliedKeys

    foreach ($t in $allToggles) {
        $lk          = Get-FeatureLookupKey -f $t.Tag
        $expectedVal = $t.Tag.Value
        $wasActive   = $beforeApply.ContainsKey($lk) -and ("$($beforeApply[$lk])" -eq "$expectedVal")
        if ($t.IsOn) {
            if (-not $wasActive) {
                try {
                    Apply-Feature -f $t.Tag
                    $logLines += @{ Text = "  ENABLED   $($t.Tag.Name)"; Color = "Green" }
                } catch {
                    $errors   += $t.Tag.Key
                    $logLines += @{ Text = "  ERROR     $($t.Tag.Name)  --  $($_.Exception.Message)"; Color = "Red" }
                }
            }
        } else {
            if ($wasActive) {
                try {
                    Remove-Feature -f $t.Tag
                    $logLines += @{ Text = "  DISABLED  $($t.Tag.Name)"; Color = "DarkGray" }
                } catch {
                    $errors   += $t.Tag.Key
                    $logLines += @{ Text = "  ERROR     $($t.Tag.Name)  --  $($_.Exception.Message)"; Color = "Red" }
                }
            }
        }
    }

    if ($dnsDrop.SelectedItem -and $dnsDrop.SelectedItem -ne "(unchanged)") {
        Set-DnsMode -m $dnsDrop.SelectedItem
        $logLines += @{ Text = "  DNS       Mode set to $($dnsDrop.SelectedItem)"; Color = "Cyan" }
    }

    $btnApply.Text    = "Apply"
    $btnApply.Enabled = $true

    $newApplied = Get-AppliedKeys
    for ($ti = 0; $ti -lt $allToggles.Count; $ti++) {
        $allDots[$ti].Active = $newApplied.ContainsKey($allFeatKeys[$ti]) -and
                               ("$($newApplied[$allFeatKeys[$ti]])" -eq "$($allFeatVals[$ti])")
        $allDots[$ti].Invalidate()
    }

    if ($logLines.Count -gt 0) {
        $nOn = ($allToggles | Where-Object { $_.IsOn }).Count
        Write-Host ""
        Write-Host "  $(Get-Date -Format 'HH:mm:ss')  Apply" -ForegroundColor White
        Write-Host "  $('-' * 48)" -ForegroundColor DarkGray
        foreach ($l in $logLines) { Write-Host $l.Text -ForegroundColor $l.Color }
        Write-Host "  $('-' * 48)" -ForegroundColor DarkGray
        if ($errors.Count -eq 0) {
            Write-Host "  Done  -  $($logLines.Count) change(s)  -  $nOn active" -ForegroundColor DarkGray
        }
    }

    if ($errors.Count -gt 0) {
        [DarkDialog]::Show("Errors on: " + ($errors -join ", "), 3)
    } else {
        $nOn  = ($allToggles | Where-Object { $_.IsOn }).Count
        $nOff = $allToggles.Count - $nOn
        [DarkDialog]::Show("Applied.`nRestart Brave then verify at brave://policy", 1)
    }
})

$btnReset.Add_Click({
    if ([DarkDialog]::Confirm("Remove ALL Brave policies from the registry and restore defaults?")) {
        try {
            if (Test-Path $REG_PATH) { Remove-Item -Path $REG_PATH -Recurse -Force }
            New-Item -Path $REG_PATH -Force | Out-Null
            foreach ($t in $allToggles) { $t.IsOn     = $false }
            foreach ($d in $allDots)    { $d.Active   = $false; $d.Invalidate() }
            $dnsDrop.SelectedIndex = 0
            Write-Host ""
            Write-Host "  $(Get-Date -Format 'HH:mm:ss')  Reset" -ForegroundColor White
            Write-Host "  $('-' * 48)" -ForegroundColor DarkGray
            Write-Host "  All Brave policies removed from registry." -ForegroundColor DarkGray
            Write-Host "  $('-' * 48)" -ForegroundColor DarkGray
            [DarkDialog]::Show("All policies removed. Restart Brave to apply.", 1)
        } catch {
            Write-Host "[ERROR]  $($_.ToString())" -ForegroundColor Red
            [DarkDialog]::Show("Error: " + $_.ToString(), 3)
        }
    }
})

$btnExport.Add_Click({
    $dlg                  = New-Object System.Windows.Forms.SaveFileDialog
    $dlg.Filter           = "JSON (*.json)|*.json"
    $dlg.FileName         = "BraveOptimizer_config.json"
    $dlg.InitialDirectory = [Environment]::GetFolderPath("MyDocuments")
    if ($dlg.ShowDialog() -eq [System.Windows.Forms.DialogResult]::OK) {
        $onToggles = @(for ($ti = 0; $ti -lt $allToggles.Count; $ti++) { if ($allToggles[$ti].IsOn) { $allFeatKeys[$ti] } })
        $exp = @{
            Features = $onToggles
            DnsMode  = if ($dnsDrop.SelectedItem -ne "(unchanged)") { $dnsDrop.SelectedItem } else { $null }
        }
        try {
            $exp | ConvertTo-Json -Depth 3 | Out-File -FilePath $dlg.FileName -Encoding UTF8 -Force
            Write-Host ""
            Write-Host "  $(Get-Date -Format 'HH:mm:ss')  Export  --  $($dlg.FileName)" -ForegroundColor DarkGray
            [DarkDialog]::Show("Exported to:`n" + $dlg.FileName, 1)
        } catch {
            Write-Host "  ERROR  $($_.ToString())" -ForegroundColor Red
            [DarkDialog]::Show("Error: " + $_.ToString(), 3)
        }
    }
})

$btnImport.Add_Click({
    $dlg                  = New-Object System.Windows.Forms.OpenFileDialog
    $dlg.Filter           = "JSON (*.json)|*.json"
    $dlg.InitialDirectory = [Environment]::GetFolderPath("MyDocuments")
    if ($dlg.ShowDialog() -eq [System.Windows.Forms.DialogResult]::OK) {
        try {
            $cfg = Get-Content -Path $dlg.FileName -Raw -Encoding UTF8 | ConvertFrom-Json
            foreach ($t in $allToggles) { $t.IsOn = $false }
            if ($cfg.Features -ne $null) {
                foreach ($key in $cfg.Features) {
                    $keyStr = [string]$key
                    for ($ti = 0; $ti -lt $allToggles.Count; $ti++) {
                        if (([string]$allFeatKeys[$ti]) -eq $keyStr -or ([string]$allToggles[$ti].Tag.Key) -eq $keyStr) {
                            $allToggles[$ti].IsOn = $true; break
                        }
                    }
                }
            }
            if ($cfg.DnsMode) {
                $idx = $dnsDrop.Items.IndexOf([string]$cfg.DnsMode)
                if ($idx -ge 0) { $dnsDrop.SelectedIndex = $idx }
            }
            $n = ($allToggles | Where-Object { $_.IsOn }).Count
            Write-Host ""
            Write-Host "  $(Get-Date -Format 'HH:mm:ss')  Import  --  $n policies from $($dlg.FileName)" -ForegroundColor DarkGray
            [DarkDialog]::Show("$n policy/policies loaded.", 0)
        } catch {
            Write-Host "[ERROR]  $($_.ToString())" -ForegroundColor Red
            [DarkDialog]::Show("Error: " + $_.ToString(), 3)
        }
    }
})

[void]$form.ShowDialog()

if ($script:_ownConsole) { [Win32.ConsoleHelper]::FreeConsole() | Out-Null }